mapper.select:
SELECT * FROM ( SELECT aal.log_id AS logId, au.name AS adminName, ar.role_code AS roleCode, aal.action AS action, aal.result AS result, aal.target_id AS targetId, aal.detail AS detail, aal.client_ip AS clientIp, aal.request_uri AS requestUri, TO_CHAR(aal.occurred_at, 'YYYY-MM-DD HH24:MI:SS') AS occurredAt, ROW_NUMBER() OVER (ORDER BY aal.occurred_at DESC) AS rn FROM ADMIN_ACTIVITY_LOG aal JOIN ADMIN_USERS au ON aal.admin_id = au.admin_id JOIN ADMIN_USER_ROLES aur ON au.admin_id = aur.admin_id AND aur.deleted_yn = 'N' JOIN ADMIN_ROLES ar ON aur.role_id = ar.role_id AND ar.deleted_yn = 'N' WHERE 1=1
AND au.name LIKE '%' || #{adminName} || '%'
AND ar.role_code = #{roleCode, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND aal.result = #{result, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND aal.occurred_at >= TO_TIMESTAMP(#{from}, 'YYYY-MM-DD')
AND aal.occurred_at < TO_TIMESTAMP(#{to}, 'YYYY-MM-DD') + 1
) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{size}

SELECT COUNT(*) FROM ADMIN_ACTIVITY_LOG aal JOIN ADMIN_USERS au ON aal.admin_id = au.admin_id JOIN ADMIN_USER_ROLES aur ON au.admin_id = aur.admin_id AND aur.deleted_yn = 'N' JOIN ADMIN_ROLES ar ON aur.role_id = ar.role_id AND ar.deleted_yn = 'N' WHERE 1=1
AND au.name LIKE '%' || #{adminName} || '%'
AND ar.role_code = #{roleCode, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND aal.result = #{result, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND aal.occurred_at >= TO_TIMESTAMP(#{from}, 'YYYY-MM-DD')
AND aal.occurred_at < TO_TIMESTAMP(#{to}, 'YYYY-MM-DD') + 1

SELECT * FROM ( SELECT al.log_id AS logId, al.action_type AS action, al.result_code AS result, al.client_ip AS clientIp, al.request_uri AS requestUri, al.detail AS detail, TO_CHAR(al.created_at, 'YYYY-MM-DD HH24:MI:SS') AS occurredAt, ROW_NUMBER() OVER (ORDER BY al.created_at DESC) AS rn FROM AUDIT_LOGS al WHERE 1=1
AND al.action_type = #{action, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND al.result_code = #{result, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND al.client_ip LIKE '%' || #{ip} || '%'
AND al.created_at >= TO_TIMESTAMP(#{from}, 'YYYY-MM-DD')
AND al.created_at < TO_TIMESTAMP(#{to}, 'YYYY-MM-DD') + 1
) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{size}

SELECT COUNT(*) FROM AUDIT_LOGS al WHERE 1=1
AND al.action_type = #{action, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND al.result_code = #{result, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND al.client_ip LIKE '%' || #{ip} || '%'
AND al.created_at >= TO_TIMESTAMP(#{from}, 'YYYY-MM-DD')
AND al.created_at < TO_TIMESTAMP(#{to}, 'YYYY-MM-DD') + 1

SELECT * FROM ( SELECT ual.log_id AS logId, ual.action AS action, ual.result AS result, ual.target_id AS targetId, ual.detail AS detail, ual.client_ip AS clientIp, ual.request_uri AS requestUri, TO_CHAR(ual.occurred_at, 'YYYY-MM-DD HH24:MI:SS') AS occurredAt, ROW_NUMBER() OVER (ORDER BY ual.occurred_at DESC) AS rn FROM USER_ACTIVITY_LOG ual WHERE 1=1
AND ual.action LIKE #{action, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler} || '%'
AND ual.result = #{result, jdbcType=VARCHAR, typeHandler=org.apache.ibatis.type.StringTypeHandler}
AND ual.occurred_at >= TO_TIMESTAMP(#{from}, 'YYYY-MM-DD')
AND ual.occurred_at < TO_TIMESTAMP(#{to}, 'YYYY-MM-DD') + 1
) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{size}
